---显示控制器
---@class LDisplayCtrl
LDisplayCtrl = {}

local _objList = {}
local _updateTimer = nil

function LDisplayCtrl.Init()
    if not LGameSettings.isFrameInstantiate then
        return
    end
    _updateTimer = LxTimer.LoopTimeCall(LDisplayCtrl.Update, LGameSettings.instantiateInterval, false, -1)
end

function LDisplayCtrl.AddDisplay(data)
    table.insert(_objList, data)
end

function LDisplayCtrl.Update()
    if #_objList <= 0 then
        return
    end
    local data = table.remove(_objList, 1)
    InstantObjectData.DealInstantObjectData(data)
end